parameters.jsCode:
const runId = `run_${Date.now()}`;
const runAt = new Date().toISOString();
console.log(`[Pipeline] Starting run: ${runId}`);
return [{ json: { runId, runAt } }];

// Feed failed — log and swallow so other stream continues
const err = $input.item.json.error || 'Unknown error';
console.error(`[Pipeline] Earnings feed failed: ${err}`);
return [];

const err = $input.item.json.error || 'Unknown error';
console.error(`[Pipeline] Regulatory feed failed: ${err}`);
return [];

// Parse RSS XML and extract article metadata
const body = $input.item.json.data || '';
const MAX = 3; // max items per run

const blocks = (body.match(/<item>(.*?)<\/item>/gs) || []).slice(0, MAX);
const items = [];

for (const block of blocks) {
  const title   = (block.match(/<title>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/) || [])[1] || '';
  const url     = (block.match(/<link>(.*?)<\/link>/) || [])[1] || '';
  const desc    = (block.match(/<description>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/) || [])[1] || '';
  const pubDate = (block.match(/<pubDate>(.*?)<\/pubDate>/) || [])[1] || '';

  if (title && url) {
    items.push({ json: {
      title: title.trim(),
      url: url.trim(),
      description: desc.replace(/<[^>]+>/g, '').trim().slice(0, 600),
      pubDate,
      sourceType: 'earnings',
      sourceName: 'Yahoo Finance'
    }});
  }
}

console.log(`[Pipeline] Parsed ${items.length} earnings items`);
return items;

// Parse RSS and keyword-filter for AI relevance
const body = $input.item.json.data || '';
const MAX = 3;

const KEYWORDS = [
  'artificial intelligence', 'AI', 'machine learning',
  'automation', 'LLM', 'AI governance', 'AI compliance',
  'AI regulation', 'AI Act', 'cybersecurity'
];

const blocks = body.match(/<item>(.*?)<\/item>/gs) || [];
const items = [];

for (const block of blocks) {
  if (items.length >= MAX) break;

  const title   = (block.match(/<title>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/) || [])[1] || '';
  const url     = (block.match(/<link>(.*?)<\/link>/) || [])[1] || '';
  const desc    = (block.match(/<description>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/) || [])[1] || '';
  const pubDate = (block.match(/<pubDate>(.*?)<\/pubDate>/) || [])[1] || '';

  const combined = (title + ' ' + desc).toLowerCase();
  const isRelevant = KEYWORDS.some(kw => combined.includes(kw.toLowerCase()));

  if (isRelevant && title && url) {
    items.push({ json: {
      title: title.trim(),
      url: url.trim(),
      description: desc.replace(/<[^>]+>/g, '').trim().slice(0, 600),
      pubDate,
      sourceType: 'regulatory',
      sourceName: 'NIST'
    }});
  }
}

console.log(`[Pipeline] Parsed ${items.length} regulatory items`);
return items;

// Simple hash function — crypto module not available in n8n sandbox
function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash; // Convert to 32bit integer
  }
  return Math.abs(hash).toString(16).padStart(8, '0');
}

const items = $input.all();
const result = [];

for (const item of items) {
  const { title, url } = item.json;
  if (!title || !url) continue;

  const hash = simpleHash(title + url);

  result.push({
    json: {
      ...item.json,
      hash
    }
  });
}

console.log(`[Pipeline] ${result.length} items ready for memory check`);
return result;

// If Postgres returned a row → duplicate, skip
// If empty → new item, pass through
const result = $input.item.json;
if (Array.isArray(result) && result.length > 0) {
  console.log(`[Pipeline] Duplicate skipped: ${result[0]?.hash}`);
  return [];
}
return [$input.item];

// Build Brand DNA style config and inject into AI prompt
const brandDNA = {
  voice: 'Direct, sharp, slightly contrarian. Practitioner who has seen things fail.',
  hook: 'Open with a surprising stat or uncomfortable truth. Never start with I or In todays.',
  structure: 'Short punchy paragraphs. Max 2 sentences each.',
  cta: 'End with a quiet open question — not a hard sell.',
  length: '150-220 words',
  emoji: 'Maximum 1, only for directional emphasis like arrow down',
  hashtags: 'Exactly 3, always on the very last line',
  forbidden: 'leverage, synergy, ecosystem, game-changer, delve, robust, seamless, cutting-edge',
  rules: [
    'Always anchor to real data or a named source',
    'Never make predictions — focus on what the data shows now',
    'Every paragraph should feel like it is about the reader, not the writer',
    'If it sounds like a vendor pitch, rewrite it'
  ]
};

const item = $input.item.json;

const prompt = `You are a ghostwriter for a senior enterprise AI practitioner publishing on LinkedIn.

BRAND DNA — NON-NEGOTIABLE RULES:
Voice: ${brandDNA.voice}
Hook style: ${brandDNA.hook}
Structure: ${brandDNA.structure}
Closing: ${brandDNA.cta}
Length: ${brandDNA.length}
Emoji: ${brandDNA.emoji}
Hashtags: ${brandDNA.hashtags}
Forbidden words: ${brandDNA.forbidden}
Rules:
${brandDNA.rules.map(r => '- ' + r).join('\n')}

Write a LinkedIn post based on this ${item.sourceType} update:
Title: ${item.title}
Source: ${item.sourceName}
Summary: ${item.description}

Find the ONE most surprising or counterintuitive truth in this source and build the post around it.
Return ONLY the post text. No preamble. No quotation marks. No markdown.`;

return [{ json: { ...item, prompt } }];

// Extract post text from Gemini agent output
const output = $input.item.json.output || '';
if (!output.trim()) {
  console.error('[Pipeline] Gemini returned empty output');
  return [];
}
console.log(`[Pipeline] Post drafted — ${output.trim().split(' ').length} words`);
return [{ json: { ...$node['Inject Brand DNA1'].json, postText: output.trim() } }];

const item = $input.item.json;

// Simple hash for token without crypto
function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(16).padStart(8, '0');
}

const token = simpleHash(item.hash + 'dev-secret');

const approveUrl = `http://localhost:5678/webhook/pipeline-approval?hash=${item.hash}&token=${token}&action=approve`;
const rejectUrl  = `http://localhost:5678/webhook/pipeline-approval?hash=${item.hash}&token=${token}&action=reject`;

// Slack Block Kit
const slackBlocks = [
  { type: 'header', text: { type: 'plain_text', text: '📋 LinkedIn Post — Ready for Review' } },
  { type: 'section', fields: [
    { type: 'mrkdwn', text: `*Source:* ${item.sourceName}` },
    { type: 'mrkdwn', text: `*Type:* ${item.sourceType}` }
  ]},
  { type: 'section', text: { type: 'mrkdwn', text: `*Article:*\n${item.title}` } },
  { type: 'divider' },
  { type: 'section', text: { type: 'mrkdwn', text: `*Draft Post:*\n\`\`\`${item.postText ? item.postText.slice(0, 800) : 'Generating...'}\`\`\`` } },
  { type: 'divider' },
  { type: 'actions', elements: [
    { type: 'button', text: { type: 'plain_text', text: '✅ Approve' }, style: 'primary', url: approveUrl },
    { type: 'button', text: { type: 'plain_text', text: '❌ Reject' }, style: 'danger', url: rejectUrl }
  ]},
  { type: 'context', elements: [{ type: 'mrkdwn', text: `⏱ Expires 48h · Hash: ${item.hash ? item.hash.slice(0,8) : 'N/A'}...` }] }
];

// Gmail HTML
const gmailHtml = `<html><body style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px">
  <h2 style="color:#1a1a2e">📋 LinkedIn Post — Approval Required</h2>
  <table style="width:100%;border-collapse:collapse;margin-bottom:20px">
    <tr><td style="padding:8px;background:#f5f5f5;font-weight:bold">Source</td><td style="padding:8px">${item.sourceName}</td></tr>
    <tr><td style="padding:8px;background:#f5f5f5;font-weight:bold">Type</td><td style="padding:8px">${item.sourceType}</td></tr>
    <tr><td style="padding:8px;background:#f5f5f5;font-weight:bold">Article</td><td style="padding:8px">${item.title}</td></tr>
  </table>
  <h3>Draft Post</h3>
  <div style="background:#f9f9f9;border-left:4px solid #667eea;padding:16px;white-space:pre-wrap;font-size:14px;line-height:1.7">${item.postText || 'Generating...'}</div>
  <br/>
  <div style="text-align:center;margin:28px 0">
    <a href="${approveUrl}" style="background:#28a745;color:white;padding:14px 36px;text-decoration:none;border-radius:6px;margin-right:16px;font-weight:bold;font-size:16px">✅ Approve</a>
    <a href="${rejectUrl}" style="background:#dc3545;color:white;padding:14px 36px;text-decoration:none;border-radius:6px;font-weight:bold;font-size:16px">❌ Reject</a>
  </div>
  <p style="color:#aaa;font-size:11px;text-align:center">Expires in 48 hours · business_post_pipeline</p>
</body></html>`;

return [{ json: { ...item, token, approveUrl, rejectUrl, slackBlocks, gmailHtml } }];

parameters.query:
INSERT INTO pipeline_memory (hash, title, url, source_name, source_type, date_fetched, status)
VALUES ('{{ $json.hash }}', '{{ $json.title.replace(/'/g, "''") }}', '{{ $json.url }}', '{{ $json.sourceName }}', '{{ $json.sourceType }}', NOW(), 'pending_approval')
ON CONFLICT (hash) DO NOTHING;

parameters.jsCode:
// Validate HMAC token — prevents spoofed approvals
const { hash, token, action } = $input.item.json.query || {};
if (!hash || !token || !['approve','reject'].includes(action)) {
  return [{ json: { valid: false, reason: 'Bad parameters' } }];
}
const expected = require('crypto')
  .createHmac('sha256', process.env.APPROVAL_WEBHOOK_SECRET || 'dev-secret')
  .update(hash).digest('hex').slice(0, 16);
if (token !== expected) {
  console.error(`[Pipeline] Invalid token for hash ${hash}`);
  return [{ json: { valid: false, reason: 'Invalid token' } }];
}
console.log(`[Pipeline] Decision: ${action} — hash: ${hash}`);
return [{ json: { valid: true, hash, action } }];
